SELECT t1.permission FROM mk_sys_permissions AS t1 LEFT JOIN mk_sys_role_permissions AS t2 ON t1.id = t2.permission_id WHERE t1.is_delete = 0 AND t2.role_id IN
#{item}
GROUP BY t1.id

SELECT `id`, `name`, `permission`, `keep_alive`, `type`, `parent_id` AS pid FROM `mk_sys_permissions` WHERE `is_delete` = 0
AND `parent_id` = #{parentId}
AND `keep_alive` = 0 AND `type` IN (-1, 0, 1)
